import json
import re
from dataclasses import dataclass
from pathlib import Path
from typing import Dict, List, Optional, Tuple

import torch
from peft import PeftModel
from PIL import Image
from transformers import AutoProcessor, Qwen2_5_VLForConditionalGeneration

DEFAULT_MIN_PIXELS = 256 * 28 * 28
DEFAULT_MAX_PIXELS = 512 * 28 * 28
GRID_SIZE = 1000.0


@dataclass
class ParsedPrediction:
    kind: str
    values: List[float]
    raw_text: str = ""


def _has_weights(path: Path) -> bool:
    if not path.exists() or not path.is_dir():
        return False
    for name in [
        "model.safetensors",
        "model.safetensors.index.json",
        "pytorch_model.bin",
        "pytorch_model.bin.index.json",
        "model-00001-of-00002.safetensors",
    ]:
        if (path / name).exists():
            return True
    return False


def _read_meta(ckpt_dir: Path) -> Dict:
    meta_path = ckpt_dir / "meta.json"
    if meta_path.exists():
        try:
            return json.loads(meta_path.read_text())
        except Exception:
            return {}
    return {}


def resolve_base_model_dir(checkpoint: str) -> str:
    ckpt = Path(checkpoint).resolve()
    ckpt_dir = ckpt if ckpt.is_dir() else ckpt.parent
    meta = _read_meta(ckpt_dir)
    cwd = Path.cwd().resolve()

    candidates = [
        ckpt_dir / "base_model",
        ckpt_dir.parent / "base_model",
        ckpt_dir.parent / "baseline" / "base_model",
        ckpt_dir.parent.parent / "baseline" / "base_model",
        cwd / "checkpoints" / "qwen_lora_small" / "base_model",
        cwd / "checkpoints" / "baseline" / "base_model",
        cwd / "checkpoints" / "base_model",
        cwd / "baseline" / "base_model",
        Path("/workspace/checkpoints/qwen_lora_small/base_model"),
        Path("/workspace/checkpoints/baseline/base_model"),
        Path("/workspace/checkpoints/base_model"),
        Path("/workspace/baseline/base_model"),
    ]

    for key in ["base_model_dir", "base_model", "base_dir"]:
        val = meta.get(key)
        if not val:
            continue
        p = Path(val)
        if p.is_absolute():
            candidates.append(p)
        else:
            candidates.append((ckpt_dir / p).resolve())
            candidates.append((cwd / p).resolve())

    seen = set()
    ordered = []
    for p in candidates:
        s = str(p)
        if s not in seen:
            seen.add(s)
            ordered.append(p)

    for p in ordered:
        if _has_weights(p):
            return str(p)
    raise FileNotFoundError(f"Could not find packaged base model for checkpoint {checkpoint}; tried: {[str(x) for x in ordered]}")


def load_processor(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    ckpt = Path(checkpoint).resolve()
    base = Path(resolve_base_model_dir(checkpoint))
    candidates = []
    if (ckpt / "processor").exists():
        candidates.append(ckpt / "processor")
    candidates.append(ckpt)
    if (base / "processor").exists():
        candidates.append(base / "processor")
    candidates.append(base)

    last_err = None
    for cand in candidates:
        try:
            return AutoProcessor.from_pretrained(
                str(cand),
                local_files_only=True,
                trust_remote_code=False,
                min_pixels=min_pixels,
                max_pixels=max_pixels,
            )
        except Exception as e:
            last_err = e
    raise last_err


def load_model_for_inference(checkpoint: str, min_pixels: int = DEFAULT_MIN_PIXELS, max_pixels: int = DEFAULT_MAX_PIXELS):
    base_dir = resolve_base_model_dir(checkpoint)
    processor = load_processor(checkpoint, min_pixels=min_pixels, max_pixels=max_pixels)
    model = Qwen2_5_VLForConditionalGeneration.from_pretrained(
        base_dir,
        torch_dtype=torch.bfloat16,
        local_files_only=True,
        trust_remote_code=False,
        device_map="auto",
    )
    ckpt_dir = Path(checkpoint).resolve()
    if (ckpt_dir / "adapter_config.json").exists():
        model = PeftModel.from_pretrained(model, str(ckpt_dir), local_files_only=True)
    model.eval()
    return model, processor


def build_messages(instruction: str):
    prompt = (
        "Identify the GUI target referred to by the instruction. "
        "Return only coordinates on a 0-1000 grid. "
        "Preferred format: <point>x y</point>. "
        "Alternative valid formats: <box>x1 y1 x2 y2</box>, <bbox>(x1,y1),(x2,y2)</bbox>, point: x, y, or x y. "
        "No explanation.\n"
        f"Instruction: {instruction}"
    )
    return [
        {
            "role": "user",
            "content": [
                {"type": "image", "image": None},
                {"type": "text", "text": prompt},
            ],
        }
    ]


def _extract_numbers(text: str) -> List[float]:
    return [float(x) for x in re.findall(r"-?\d+(?:\.\d+)?", text)]


def clip_point(x: float, y: float, width: float, height: float) -> List[float]:
    return [max(0.0, min(float(width), float(x))), max(0.0, min(float(height), float(y)))]


def clip_bbox(x1: float, y1: float, x2: float, y2: float, width: float, height: float) -> List[float]:
    x1 = max(0.0, min(float(width), float(x1)))
    x2 = max(0.0, min(float(width), float(x2)))
    y1 = max(0.0, min(float(height), float(y1)))
    y2 = max(0.0, min(float(height), float(y2)))
    xa, xb = sorted([x1, x2])
    ya, yb = sorted([y1, y2])
    return [xa, ya, xb, yb]


def _scale_grid_to_abs(nums: List[float], width: float, height: float) -> List[float]:
    out = []
    for i, v in enumerate(nums):
        if i % 2 == 0:
            out.append(v / GRID_SIZE * width)
        else:
            out.append(v / GRID_SIZE * height)
    return out


def _parse_attr_point(text: str) -> Optional[ParsedPrediction]:
    m = re.search(r"<point[^>]*x1\s*=\s*\"?([\d.]+)\"?[^>]*y1\s*=\s*\"?([\d.]+)\"?[^>]*>", text, flags=re.I)
    if m:
        return ParsedPrediction("point", [float(m.group(1)), float(m.group(2))], text)
    m = re.search(r"<point[^>]*x\s*=\s*\"?([\d.]+)\"?[^>]*y\s*=\s*\"?([\d.]+)\"?[^>]*>", text, flags=re.I)
    if m:
        return ParsedPrediction("point", [float(m.group(1)), float(m.group(2))], text)
    return None


def parse_prediction_text(text: str) -> Optional[ParsedPrediction]:
    if not text:
        return None
    t = text.strip()

    attr = _parse_attr_point(t)
    if attr is not None:
        return attr

    patterns = [
        ("point", r"<point>\s*([\d.\-]+)[,\s]+([\d.\-]+)\s*</point>"),
        ("box", r"<box>\s*([\d.\-]+)[,\s]+([\d.\-]+)[,\s]+([\d.\-]+)[,\s]+([\d.\-]+)\s*</box>"),
        ("box", r"<bbox>\s*\(?\s*([\d.\-]+)\s*,\s*([\d.\-]+)\s*\)?\s*,?\s*\(?\s*([\d.\-]+)\s*,\s*([\d.\-]+)\s*\)?\s*</bbox>"),
        ("point", r"point\s*[:=]\s*\(?\s*([\d.\-]+)\s*,\s*([\d.\-]+)\s*\)?"),
        ("box", r"bbox\s*[:=]\s*\(?\s*([\d.\-]+)\s*,\s*([\d.\-]+)\s*,\s*([\d.\-]+)\s*,\s*([\d.\-]+)\s*\)?"),
    ]
    for kind, pat in patterns:
        m = re.search(pat, t, flags=re.I | re.S)
        if m:
            vals = [float(g) for g in m.groups()]
            return ParsedPrediction(kind, vals, t)

    nums = _extract_numbers(t)
    if len(nums) >= 4:
        return ParsedPrediction("box", nums[:4], t)
    if len(nums) >= 2:
        return ParsedPrediction("point", nums[:2], t)
    return None


def prediction_to_abs(parsed: ParsedPrediction, width: float, height: float) -> Dict[str, List[float]]:
    vals = parsed.values
    if parsed.kind == "box":
        scaled = _scale_grid_to_abs(vals[:4], width, height)
        bbox = clip_bbox(*scaled, width, height)
        cx = 0.5 * (bbox[0] + bbox[2])
        cy = 0.5 * (bbox[1] + bbox[3])
        return {"bbox": bbox, "point": clip_point(cx, cy, width, height)}
    scaled = _scale_grid_to_abs(vals[:2], width, height)
    pt = clip_point(scaled[0], scaled[1], width, height)
    return {"point": pt}


def fallback_from_text(text: str, width: float, height: float) -> Dict[str, List[float]]:
    nums = _extract_numbers(text or "")
    if len(nums) >= 2:
        scaled = _scale_grid_to_abs(nums[:2], width, height)
        return {"point": clip_point(scaled[0], scaled[1], width, height)}
    return {"point": [width / 2.0, height / 2.0]}


def generate_raw(model, processor, image: Image.Image, instruction: str, max_new_tokens: int = 32) -> str:
    messages = build_messages(instruction)
    prompt = processor.apply_chat_template(messages, tokenize=False, add_generation_prompt=True)
    inputs = processor(
        text=[prompt],
        images=[image],
        padding=True,
        return_tensors="pt",
    )
    inputs = {k: v.to(model.device) if hasattr(v, "to") else v for k, v in inputs.items()}
    with torch.no_grad():
        output_ids = model.generate(
            **inputs,
            max_new_tokens=max_new_tokens,
            do_sample=False,
            use_cache=True,
        )
    gen_ids = output_ids[:, inputs["input_ids"].shape[1]:]
    text = processor.batch_decode(gen_ids, skip_special_tokens=True, clean_up_tokenization_spaces=False)[0]
    return text.strip()


def generate_prediction(model, processor, image: Image.Image, instruction: str, width: float, height: float) -> Dict[str, List[float]]:
    raw = generate_raw(model, processor, image, instruction)
    parsed = parse_prediction_text(raw)
    if parsed is None:
        pred = fallback_from_text(raw, width, height)
    else:
        pred = prediction_to_abs(parsed, width, height)
    if "point" in pred:
        pred["point"] = clip_point(pred["point"][0], pred["point"][1], width, height)
    if "bbox" in pred:
        pred["bbox"] = clip_bbox(*pred["bbox"], width, height)
    return pred
